#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 2e6+5;
const LL INF = 0x3f3f3f3f3f3f3f3f;
LL n,p,q,x,y,Ans;
LL a[N],sum[N];
LL dq[N],st,ed;
string s;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}

int main(){
    n=read(),p=read(),q=read();
    x=read(),y=read();
    cin>>s;s=" "+s;
    for(int i=1;i<=n;i++)
        a[i]=(s[i]=='+'?1:-1),
        sum[i]=sum[i-1]+a[i];
    for(int i=n+1;i<=2*n;i++)
        sum[i]=sum[i-1]+a[i-n];
    st=1,ed=0;
    LL ned=p+sum[n],d=abs(q-ned)/2*x;
    Ans=INF,sum[0]=-INF;
    for(int i=0;i<=n;i++){
        while(st<=ed&&sum[dq[ed]]>=sum[i])ed--;
        dq[++ed]=i;
    }
    for(int i=n+1;i<=2*n;i++){
        while(st<=ed&&sum[dq[ed]]>=sum[i])ed--;
        dq[++ed]=i;
        while(st<=ed&&dq[st]<i-n)st++;
        if(st>ed)continue;
        LL k=2*n-i;
        LL val=sum[dq[st]]-sum[i-n]+p+max(q-ned,0ll);
        LL tmp=max(1-val,0ll)/2*2*x;
        Ans=min(Ans,k*y+tmp);
    }
    cout<<Ans+d<<"\n";
    return 0;
}
